// nextPageURL builds the URL for the next page of channel videos.
func nextPageURL(channelID string, page int, search string) string {
	u := fmt.Sprintf("/channels/%s?page=%d", channelID, page)
	if search != "" {
		u += "&q=" + search
	}
	return u
}

